"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Mic, Send, RefreshCcw, Command, Activity, Heart, ShieldAlert, Zap, MessageSquare, ChevronRight } from "lucide-react";
import { VoiceAnalysisResult } from "@/lib/voice-analyzer";

export default function Home() {
  const [text, setText] = useState("");
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<VoiceAnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleAnalyze = async () => {
    if (!text.trim()) return;

    setIsAnalyzing(true);
    setError(null);

    try {
      const response = await fetch("/api/analyze", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ text }),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.message || "Failed to analyze text");
      }

      setResult(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      handleAnalyze();
    }
  };

  const examples = [
    "Do this now!",
    "Can you help me with this please?",
    "Oh great, another bug. Really impressive work.",
    "I've already tried that three times, why isn't it working?",
  ];

  const getScoreColor = (score: number) => {
    if (score < 30) return "bg-red-500";
    if (score < 60) return "bg-yellow-500";
    if (score < 80) return "bg-blue-500";
    return "bg-green-500";
  };

  const ScoreBar = ({ label, score, icon: Icon }: { label: string, score: number, icon: any }) => (
    <div className="mb-4">
      <div className="flex justify-between items-center mb-1.5">
        <span className="text-sm font-medium text-gray-300 flex items-center gap-2">
          <Icon size={14} className="text-gray-400" />
          {label}
        </span>
        <span className="text-sm font-bold text-white">{score}/100</span>
      </div>
      <div className="w-full bg-gray-800 rounded-full h-2 overflow-hidden border border-gray-700">
        <motion.div 
          initial={{ width: 0 }}
          animate={{ width: \`\${score}%\` }}
          transition={{ duration: 1, ease: "easeOut" }}
          className={\`h-2 rounded-full \${getScoreColor(score)}\`}
        />
      </div>
    </div>
  );

  return (
    <main className="min-h-screen p-4 md:p-8 lg:p-12 max-w-6xl mx-auto flex flex-col items-center">
      {/* Header */}
      <motion.div 
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full text-center mb-12"
      >
        <div className="inline-flex items-center justify-center p-3 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 mb-6">
          <Mic className="text-indigo-400 w-8 h-8" />
        </div>
        <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight mb-4 text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400">
          Voice AI Agent
        </h1>
        <p className="text-gray-400 text-lg max-w-2xl mx-auto">
          Intelligent Communication Analyzer. Paste your transcribed speech below to analyze emotional tone, classify intent, and receive suggestions.
        </p>
      </motion.div>

      {/* Main Content Area */}
      <div className="w-full grid grid-cols-1 lg:grid-cols-12 gap-8 relative z-10">

        {/* Input Column */}
        <motion.div 
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ delay: 0.1 }}
          className="lg:col-span-5 flex flex-col gap-6"
        >
          <div className="glass-panel p-6">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <MessageSquare size={18} className="text-indigo-400" />
              Transcribed Speech
            </h2>

            <div className="relative">
              <textarea
                value={text}
                onChange={(e) => setText(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Type or paste your transcribed speech here..."
                className="w-full h-48 bg-black/40 border border-gray-700 rounded-xl p-4 text-gray-100 placeholder-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 transition-all resize-none"
              />
              <div className="absolute bottom-3 right-3 text-xs text-gray-600 font-medium">
                Ctrl + Enter to send
              </div>
            </div>

            {error && (
              <div className="mt-4 p-3 rounded-lg bg-red-500/10 border border-red-500/20 text-red-400 text-sm flex items-start gap-2">
                <ShieldAlert size={16} className="mt-0.5 shrink-0" />
                <span>{error}</span>
              </div>
            )}

            <button
              onClick={handleAnalyze}
              disabled={isAnalyzing || !text.trim()}
              className="w-full mt-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-500 hover:to-purple-500 text-white font-semibold py-3 px-6 rounded-xl shadow-lg border border-indigo-500/50 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center justify-center gap-2 group"
            >
              {isAnalyzing ? (
                <>
                  <RefreshCcw className="animate-spin" size={18} />
                  Analyzing...
                </>
              ) : (
                <>
                  <Activity size={18} className="group-hover:animate-pulse" />
                  Analyze Communication
                </>
              )}
            </button>
          </div>

          <div className="glass-panel p-6">
            <h3 className="text-sm font-semibold text-gray-400 mb-3 uppercase tracking-wider">Try an Example</h3>
            <div className="flex flex-col gap-2">
              {examples.map((ex, i) => (
                <button
                  key={i}
                  onClick={() => setText(ex)}
                  className="text-left p-3 rounded-lg bg-white/5 hover:bg-white/10 border border-transparent hover:border-white/10 transition-all text-sm text-gray-300 break-words flex items-center justify-between group"
                >
                  <span className="line-clamp-2 pr-4">{ex}</span>
                  <ChevronRight size={14} className="text-gray-500 opacity-0 group-hover:opacity-100 transition-opacity shrink-0" />
                </button>
              ))}
            </div>
          </div>
        </motion.div>

        {/* Results Column */}
        <div className="lg:col-span-7">
          <AnimatePresence mode="wait">
            {!result ? (
              <motion.div 
                key="empty"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="h-full min-h-[400px] glass-panel p-8 flex flex-col items-center justify-center text-center border-dashed border-2 border-gray-700/50"
              >
                <div className="w-20 h-20 rounded-full bg-gray-800/50 flex items-center justify-center mb-6">
                  <Zap className="text-gray-600 w-8 h-8" />
                </div>
                <h3 className="text-xl font-medium text-gray-300 mb-2">Awaiting Input</h3>
                <p className="text-gray-500 max-w-sm">
                  Enter some text and click Analyze to reveal deep structural insights about the communication.
                </p>
              </motion.div>
            ) : (
              <motion.div 
                key="results"
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                className="space-y-6"
              >
                {/* Top Tiles */}
                <div className="grid grid-cols-2 gap-4">
                  <div className="glass-panel p-5">
                    <span className="text-xs font-semibold text-gray-400 uppercase tracking-wider block mb-3">Detected Tone</span>
                    <div className={\`tone-badge tone-\${result.tone.toLowerCase()}\`}>
                      <span className="w-2 h-2 rounded-full bg-current"></span>
                      {result.tone}
                    </div>
                  </div>
                  <div className="glass-panel p-5">
                    <span className="text-xs font-semibold text-gray-400 uppercase tracking-wider block mb-3">Detected Intent</span>
                    <span className="intent-badge">{result.intent}</span>
                  </div>
                </div>

                {/* Main Analysis Card */}
                <div className="glass-panel p-6">
                  <h3 className="text-lg font-semibold mb-6 flex items-center gap-2 border-b border-gray-800 pb-4">
                    <Activity size={18} className="text-indigo-400" />
                    Behavioral Analysis
                  </h3>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-6">
                      <ScoreBar label="Politeness" score={result.politeness_score} icon={Heart} />
                      <ScoreBar label="Confidence" score={result.confidence_score} icon={Command} />
                      <ScoreBar label="Emotion Intensity" score={result.emotion_intensity} icon={Zap} />
                    </div>

                    <div className="bg-black/30 rounded-xl p-5 border border-gray-800 flex flex-col justify-center">
                      <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider block mb-2">Dominant Emotion</span>
                      <span className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-pink-400 to-orange-400 capitalize">
                        {result.emotion}
                      </span>
                    </div>
                  </div>
                </div>

                {/* Improved Text Card */}
                <div className="glass-panel p-6 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-indigo-500 to-purple-500"></div>
                  <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                    <Send size={18} className="text-indigo-400" />
                    Suggested Improvement
                  </h3>
                  <div className="bg-white/5 rounded-xl p-5 border border-white/10 relative group">
                    <p className="text-lg text-white leading-relaxed font-medium">
                      "{result.improved_text}"
                    </p>
                  </div>
                </div>

                {/* Raw JSON Debug - Kept exactly as requested by PRD for Technical Validation */}
                <div className="glass-panel p-4">
                  <details className="group cursor-pointer">
                    <summary className="text-xs font-semibold text-gray-500 uppercase tracking-wider flex items-center gap-2 outline-none">
                      <ChevronRight size={14} className="group-open:rotate-90 transition-transform" />
                      View Raw JSON Payload
                    </summary>
                    <div className="mt-4 bg-black/50 p-4 rounded-lg overflow-x-auto border border-gray-800">
                      <pre className="text-xs text-green-400 font-mono">
                        {JSON.stringify(result, null, 2)}
                      </pre>
                    </div>
                  </details>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </main>
  );
}

// A simple test script to evaluate the AI Agent against PRD benchmarks
// Required to run via tsx: `npx tsx scripts/evaluate.ts`

import "process";

const API_URL = "http://localhost:3000/api/analyze";

const tests = [
  { id: "T-01", input: "Do this now!", expectedTone: "commanding", expectedIntent: "command" },
  { id: "T-02", input: "Can you please help me?", expectedTone: "polite", expectedIntent: "request" },
  { id: "T-03", input: "Why is this still broken?!", expectedTone: "frustrated", expectedIntent: "complaint" },
  { id: "T-04", input: "Oh great, another crash.", expectedTone: "sarcastic", expectedIntent: "complaint" },
  { id: "T-05", input: "Good morning!", expectedTone: "friendly", expectedIntent: "greeting" },
  { id: "T-06", input: "The file is on the server.", expectedTone: "neutral", expectedIntent: "information" },
  { id: "T-07", input: "YOU NEVER LISTEN TO ME.", expectedTone: "angry", expectedIntent: "complaint" },
  { id: "T-08", input: "Thank you so much, really helpful.", expectedTone: "polite", expectedIntent: "appreciation" },
];

async function runTests() {
  console.log("🚀 Starting Voice AI Agent Evaluation Benchmark\n");

  let passed = 0;
  let totalLatency = 0;

  for (const test of tests) {
    console.log(\`Evaluating [\${test.id}] "\${test.input}"\`);

    const start = Date.now();
    try {
      const response = await fetch(API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ text: test.input }),
      });

      const latency = Date.now() - start;
      totalLatency += latency;

      if (!response.ok) {
        console.error(\`❌ API Error: \${response.statusText}\`);
        continue;
      }

      const data = await response.json();

      const toneMatch = data.tone === test.expectedTone;
      const intentMatch = data.intent === test.expectedIntent;

      if (toneMatch && intentMatch) {
        console.log(\`✅ Passed - Tone: \${data.tone}, Intent: \${data.intent} (\${latency}ms)\`);
        passed++;
      } else {
        console.log(\`❌ Failed (\${latency}ms)\`);
        if (!toneMatch) console.log(\`   Expected Tone: \${test.expectedTone}, Got: \${data.tone}\`);
        if (!intentMatch) console.log(\`   Expected Intent: \${test.expectedIntent}, Got: \${data.intent}\`);
      }

    } catch (e: any) {
        console.error(\`❌ Error running test \${test.id}: \${e.message}\`);
    }
    console.log("------------------------------------------");
  }

  const avgLatency = (totalLatency / tests.length).toFixed(0);
  console.log(\`\n📊 Benchmark Results: \${passed}/\${tests.length} Passed\`);
  console.log(\`⏱️ Average Latency: \${avgLatency}ms\`);
  if (parseInt(avgLatency) > 2000) {
      console.warn("⚠️ Warning: Average latency exceeds NFR-1 requirement of 2 seconds.");
  } else {
      console.log("✅ Latency meets NFR-1 requirements.");
  }
}

// Check if server is running before executing
fetch(API_URL, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ text: "test" }) })
    .then(() => runTests())
    .catch((e) => {
        console.error("❌ Cannot connect to API. Please ensure the Next.js server is running (`npm run dev`) before executing this script.");
    });
